package net.orbitalstrike.server;import net.fabricmc.fabric.api.event.lifecycle.v1.ServerTickEvents;import net.fabricmc.fabric.api.networking.v1.ServerPlayNetworking;import net.minecraft.entity.Entity;import net.minecraft.entity.TntEntity;import net.minecraft.entity.EntityType;import net.minecraft.server.MinecraftServer;import net.minecraft.server.network.ServerPlayerEntity;import net.minecraft.server.world.ServerWorld;import net.minecraft.util.TypeFilter;import net.minecraft.world.GameMode;import net.orbitalstrike.network.TntUpdatePayload;import java.util.ArrayList;import java.util.List;public class ServerTntTracker {    public static void register() {        ServerTickEvents.END_SERVER_TICK.register(ServerTntTracker::onTick);    }    private static void onTick(MinecraftServer server) {        List<TntUpdatePayload.TntEntry> all = new ArrayList<>();        for (ServerWorld world : server.getWorlds()) {            world.getEntitiesByType(                    TypeFilter.instanceOf(TntEntity.class),                    tnt -> true            ).forEach(tnt -> {                int cx = tnt.getBlockPos().getX() >> 4;                int cz = tnt.getBlockPos().getZ() >> 4;                boolean lazy = !world.getChunkManager().isChunkLoaded(cx, cz);                all.add(new TntUpdatePayload.TntEntry(                        tnt.getUuid(),                        tnt.getX(), tnt.getY(), tnt.getZ(),                        tnt.getYaw(), tnt.getPitch(),                        tnt.getFuse(),                        lazy                ));            });        }        if (all.isEmpty()) return;        TntUpdatePayload payload = new TntUpdatePayload(all);        for (ServerPlayerEntity player : server.getPlayerManager().getPlayerList()) {            if (player.interactionManager.getGameMode() == GameMode.SPECTATOR) {                ServerPlayNetworking.send(player, payload);            }        }    }}